<div class="table-responsive"><table class="table align-middle"><thead><tr><th>Fecha</th><th>Evento</th><th>Rol / modo</th><th>Módulo y acción</th><th>Resultado</th><th>Descripción / correlación</th></tr></thead><tbody><?php foreach($actividad as$evento):?><tr><td class="text-nowrap"><?=date('d/m/Y H:i',strtotime((string)$evento['created_at']))?></td><td><?=atenea_e((string)$evento['event_type'])?></td><td><?=atenea_e((string)($evento['actor_role']?:'sin rol'))?><small class="d-block text-muted"><?=atenea_e((string)($evento['active_mode']?:'sin modo'))?></small></td><td><?=atenea_e((string)$evento['module'])?><small class="d-block text-muted"><?=atenea_e((string)$evento['action'])?></small></td><td><span class="badge badge-opacity-<?=$evento['result']==='success'?'success':'danger'?>"><?=atenea_e((string)$evento['result'])?></span></td><td><?=atenea_e((string)$evento['description'])?><small class="d-block text-muted">ID: <?=atenea_e((string)$evento['request_id'])?></small></td></tr><?php endforeach;?><?php if(!$actividad):?><tr><td colspan="6" class="text-center text-muted">Sin actividad registrada.</td></tr><?php endif;?></tbody></table></div>
<?php $auditPaginas=max(1,(int)ceil($auditTotal/$limite));if($auditPaginas>1):?><nav aria-label="Páginas de actividad"><ul class="pagination justify-content-end"><?php for($p=1;$p<=$auditPaginas;$p++):?><li class="page-item <?=$p===$auditPagina?'active':''?>"><a class="page-link" href="?id=<?=$id?>&audit_page=<?=$p?>#actividad"><?=$p?></a></li><?php endfor;?></ul></nav><?php endif;?>
